import { createPortal } from "react-dom";
import { logo } from "../../assets/images";

export default function Footer() {
  const FooterRoot = document.getElementById("Footer");

  if (!FooterRoot) return null;

  return createPortal(
    <div href="/" className="Footer-inner">
      <p>‘내가 헛되이 보낸 오늘은 어제 죽은 이가 그토록 갈망하던 내일이다’</p>
      <a href="mailto:lovesong001109@gmail.com">lovesong001109@gmail.com</a>
      <ul>
        <li><a href="tel:01054085146">010-5408-5146</a></li>
        <li><a href="https://github.com/MinJ1109" target="_blank" rel="noopener noreferrer">https://github.com/MinJ1109</a></li>
      </ul>
      <span>본 사이트는 상업적 목적이 아닌 개인의 포트폴리오용으로 제작되었습니다<span>© 2025 Minju Lee. All Rights Reserved.</span></span>
    </div>,
    FooterRoot
  );
}
